package org.jsoup.parser;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.jsoup.parser.steps"
)
public class CucumberTest {
}

package org.jsoup.parser.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import static org.junit.Assert.*;

public class StepDefs {

    private String inputHtml;
    private Document document;
    private Element preElement;

    @Given("the input HTML is {string}")
    public void the_input_HTML_is(String html) {
        this.inputHtml = html;
    }

    @When("the HTML is parsed")
    public void the_HTML_is_parsed() {
        try {
            this.document = Jsoup.parse(inputHtml);
            this.preElement = document.selectFirst("pre");
        } catch (Exception e) {
            // Handle exception in parsing
            fail("Exception occurred during HTML parsing: " + e.getMessage());
        }
    }

    @Then("the {string} element should have text {string}")
    public void the_element_should_have_text(String tagName, String expectedText) {
        assertNotNull("The " + tagName + " element was not found", preElement);
        String actualText = preElement.text();
        assertEquals("Text content does not match", expectedText, actualText);
    }

    @Then("the {string} element should have whole text {string}")
    public void the_element_should_have_whole_text(String tagName, String expectedText) {
        assertNotNull("The " + tagName + " element was not found", preElement);
        String actualText = preElement.wholeText();
        assertEquals("Whole text content does not match", expectedText, actualText);
    }
}

