import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;

public class TestPreFix {
    public static void main(String[] args) {
        // Test case 1: A single newline after pre tag should be ignored
        String html1 = "<pre>\nOne</pre>";
        Document doc1 = Jsoup.parse(html1);
        Element pre1 = doc1.selectFirst("pre");
        String text1 = pre1.text();
        System.out.println("Test 1 - Input: " + html1);
        System.out.println("Test 1 - Text: " + text1);
        System.out.println("Test 1 - Expected: 'One', Got: '" + text1 + "', Pass: " + text1.equals("One"));
        System.out.println();

        // Test case 2: Only the first newline after pre tag is ignored
        String html2 = "<pre>\n\nOne</pre>";
        Document doc2 = Jsoup.parse(html2);
        Element pre2 = doc2.selectFirst("pre");
        String text2 = pre2.wholeText();
        System.out.println("Test 2 - Input: " + html2);
        System.out.println("Test 2 - WholeText: '" + text2 + "'");
        System.out.println("Test 2 - Expected: '\\nOne', Got: '" + text2 + "'");
        boolean pass2 = text2.startsWith("\n") && text2.substring(1).equals("One");
        System.out.println("Test 2 - Pass: " + pass2);
        System.out.println();

        // Test case 3: Newline is not ignored if not immediately after pre tag
        String html3 = "<pre><!-- comment -->\nOne</pre>";
        Document doc3 = Jsoup.parse(html3);
        Element pre3 = doc3.selectFirst("pre");
        String text3 = pre3.wholeText();
        System.out.println("Test 3 - Input: " + html3);
        System.out.println("Test 3 - WholeText: '" + text3 + "'");
        boolean pass3 = text3.contains("\nOne"); // Should contain the \nOne as text
        System.out.println("Test 3 - Should contain '\\nOne': " + pass3);
    }
}

